params.bodyScript:
  const buttons = $('#w-gen-buttons');
  const re = $('#w-gen-re'), im = $('#w-gen-im');
  const out = $('#w-gen-out'), lenEl = $('#w-gen-len');
  const svg = $('#w-gen-svg');
  const W = 720, H = 300;
  // map tau -> pixel
  const xmin = -2.5, xmax = 2.5, ymax = 3;
  function px(t){ return [ (t.re - xmin)/(xmax-xmin) * W, H - (t.im/ymax) * H ]; }

  const word = []; // list of 'S' | 'T' | 'Ti'
  function matmul(A,B){
    return [[A[0][0]*B[0][0]+A[0][1]*B[1][0], A[0][0]*B[0][1]+A[0][1]*B[1][1]],
            [A[1][0]*B[0][0]+A[1][1]*B[1][0], A[1][0]*B[0][1]+A[1][1]*B[1][1]]];
  }
  const MS = [[0,-1],[1,0]];
  const MT = [[1,1],[0,1]];
  const MTi = [[1,-1],[0,1]];
  const MI = [[1,0],[0,1]];
  function gmat(g){ return g==='S'?MS:(g==='T'?MT:MTi); }

  function apply(M, t){
    const re = M[0][0]*t.re + M[0][1];
    const reDen = M[1][0]*t.re + M[1][1];
    const imNum = M[0][0]*t.im;
    const imDen = M[1][0]*t.im;
    // (a*tau+b)/(c*tau+d) with tau = re+i*im
    const a=M[0][0], b=M[0][1], c=M[1][0], d=M[1][1];
    const nr = a*t.re + b, ni = a*t.im;
    const dr = c*t.re + d, di = c*t.im;
    const denom = dr*dr + di*di;
    return { re: (nr*dr + ni*di)/denom, im: (ni*dr - nr*di)/denom };
  }

  function render(){
    svg.innerHTML = '';
    // grid
    for(let x=Math.ceil(xmin); x<=Math.floor(xmax); x++){
      const [px1] = px({re:x,im:0});
      svg.appendChild(SVG('line',{x1:px1,y1:0,x2:px1,y2:H,stroke:'var(--line)','stroke-width':1}));
    }
    for(let y=1;y<=3;y++){
      const [,py1] = px({re:0,im:y});
      svg.appendChild(SVG('line',{x1:0,y1:py1,x2:W,y2:py1,stroke:'var(--line)','stroke-width':1}));
    }
    // real axis
    svg.appendChild(SVG('line',{x1:0,y1:H-1,x2:W,y2:H-1,stroke:'var(--mute)','stroke-width':1.5}));
    // unit semicircle |tau|=1
    const path = SVG('path',{d:'',stroke:'var(--violet)','stroke-width':1.2,fill:'none','stroke-dasharray':'4 4'});
    let d='';
    for(let k=0;k<=60;k++){
      const theta = Math.PI*k/60;
      const t = {re:Math.cos(theta), im:Math.sin(theta)};
      const [X,Y] = px(t);
      d += (k===0?'M':'L') + X.toFixed(1) + ' ' + Y.toFixed(1) + ' ';
    }
    path.setAttribute('d', d);
    svg.appendChild(path);
    // fundamental-domain vertical edges at x=±1/2
    for(const x of [-0.5,0.5]){
      const [X] = px({re:x,im:0});
      svg.appendChild(SVG('line',{x1:X,y1:0,x2:X,y2:H,stroke:'var(--violet)','stroke-width':1.2,'stroke-dasharray':'4 4'}));
    }

    // orbit: start with (re,im), apply word
    let t = {re: parseFloat(re.value), im: parseFloat(im.value)};
    if(!(t.im > 0)){ t.im = 0.1; }
    const pts = [t];
    let M = MI;
    for(const g of word){
      M = matmul(gmat(g), M);
      pts.push(apply(gmat(g), pts[pts.length-1]));
    }
    // draw trail
    for(let i=1;i<pts.length;i++){
      const [x0,y0] = px(pts[i-1]);
      const [x1,y1] = px(pts[i]);
      svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x1,y2:y1,stroke:'var(--cyan)','stroke-width':1.2,'stroke-opacity':0.5}));
    }
    // points
    pts.forEach((p,i) => {
      const [X,Y] = px(p);
      if(X<0||X>W||Y<0||Y>H) return;
      const last = i === pts.length-1;
      svg.appendChild(SVG('circle',{cx:X,cy:Y,r:last?5:3,
        fill:last?'var(--yellow)':'var(--cyan)','fill-opacity':last?1:0.7}));
      if(i===0){
        const tx = SVG('text',{x:X+6,y:Y-6,'font-size':11,fill:'var(--mute)'});
        tx.textContent = 'τ₀'; svg.appendChild(tx);
      }
    });
    // readout
    const tau = pts[pts.length-1];
    out.textContent = `matrix: [[${M[0][0]}, ${M[0][1]}], [${M[1][0]}, ${M[1][1]}]]
word:   ${word.length ? word.map(g=>g==='Ti'?'T⁻¹':g).join(' · ') : '(identity)'}
τ  →  ${tau.re.toFixed(4)} + ${tau.im.toFixed(4)} i`;
    lenEl.textContent = word.length;
  }

  buttons.addEventListener('click', (e)=>{
    const g = e.target.dataset && e.target.dataset.g;
    if(!g) return;
    if(g==='clear'){ word.length = 0; }
    else word.push(g);
    render();
  });
  re.addEventListener('input', render);
  im.addEventListener('input', render);
  render();

